import X from 'lucide-solid/icons/x';
import { Component, For, JSX, Show, createEffect, createMemo, onCleanup, onMount } from 'solid-js';
import { render } from 'solid-js/web';
import { Error, Loader, Success } from './icons';
import { Info } from './icons/InfoIcon';
import { Warning } from './icons/WarningIcon';
import { toastStore } from './toast.store';
import type {
  Message,
  PromiseOptions,
  ToastAPI,
  ToastData,
  ToastOptions,
  ToastPosition,
  ToastType,
  ToasterProps,
  ValueOrFunction,
} from './toast.type';

export const getToastYDirection = (toast: ToastData, defaultPos: ToastPosition) => {
  const position = toast.position || defaultPos;
  const top = position.includes('top');
  return top ? 1 : -1;
};
// Helper to resolve value or function
const resolveValue = <TValue, TArg>(valOrFn: ValueOrFunction<TValue, TArg>, arg: TArg): TValue => {
  return typeof valOrFn === 'function' ? (valOrFn as (arg: TArg) => TValue)(arg) : valOrFn;
};

const getToastIcon = (toast: ToastData): JSX.Element | null => {
  if (toast.icon !== undefined) {
    return toast.icon as Element;
  }
  switch (toast.type) {
    case 'success':
      return <Success {...toast.iconTheme} />;
    case 'error':
      return <Error {...toast.iconTheme} />;
    case 'info':
      return <Info {...toast.iconTheme} />;
    case 'warning':
      return <Warning {...toast.iconTheme} />;
    case 'loading':
      return <Loader {...toast.iconTheme} />;
    default:
      return null;
  }
};

const CloseIcon: Component<{ onClick: () => void; isRight: boolean }> = props => {
  return (
    <div
      class={`toa03 ${props.isRight ? 'toa04' : 'toa05'}`}
      onClick={e => {
        e.stopPropagation();
        props.onClick();
      }}
      aria-label="Close"
    >
      <X size={10} stroke-width={4} />
    </div>
  );
};

const ToastBar: Component<{ toast: ToastData; position: ToastPosition }> = props => {
  const icon = createMemo(() => getToastIcon(props.toast));

  const isCloseOnRight = createMemo(() => !props.position.includes('right'));

  const handleClose = () => {
    toastStore.removeToast(props.toast.id);
  };

  return (
    <div
      class={`toa01 ${props.toast.class || ''}`}
      style={props.toast.style}
      role={props.toast.ariaProps.role}
      aria-live={props.toast.ariaProps['aria-live']}
    >
      <Show when={props.toast.showCloseIcon}>
        <CloseIcon onClick={handleClose} isRight={isCloseOnRight()} />
      </Show>
      <Show when={icon()}>{icon()}</Show>
      <div class="flex-1 text-sm">{props.toast.message as Element}</div>
    </div>
  );
};

// Individual toast wrapper with animations
const ToastWrapper: Component<{ toast: ToastData; position: ToastPosition }> = props => {
  let dismissTimer: ReturnType<typeof setTimeout> | undefined;
  let removeTimer: ReturnType<typeof setTimeout> | undefined;
  let wrapperRef: HTMLDivElement | undefined;

  // Theo dõi thời gian còn lại và thời điểm bắt đầu timer
  let remainingTime = props.toast.duration;
  let timerStartTime = 0;
  let isPaused = false;

  // Bắt đầu timer với thời gian còn lại
  const startDismissTimer = (duration: number) => {
    if (duration === Infinity || !props.toast.visible) return;

    timerStartTime = Date.now();
    dismissTimer = setTimeout(() => {
      toastStore.dismissToast(props.toast.id);
    }, duration);
  };

  // Dừng timer và lưu thời gian còn lại
  const pauseDismissTimer = () => {
    if (dismissTimer) {
      clearTimeout(dismissTimer);
      dismissTimer = undefined;
      // Tính thời gian còn lại
      const elapsed = Date.now() - timerStartTime;
      remainingTime = Math.max(0, remainingTime - elapsed);
    }
  };

  // Event handlers cho pause on hover
  const handleMouseEnter = () => {
    if (!props.toast.canPause || isPaused) return;
    isPaused = true;
    pauseDismissTimer();
  };

  const handleMouseLeave = () => {
    if (!props.toast.canPause || !isPaused) return;
    isPaused = false;
    startDismissTimer(remainingTime);
  };

  // Setup auto dismiss timer on mount
  onMount(() => {
    startDismissTimer(props.toast.duration);

    // Thêm event listeners nếu canPause = true
    if (props.toast.canPause && wrapperRef) {
      wrapperRef.addEventListener('mouseenter', handleMouseEnter);
      wrapperRef.addEventListener('mouseleave', handleMouseLeave);
    }
  });

  // Watch for visible change to schedule removal
  createEffect(function handleVisibilityChange() {
    const visible = props.toast.visible;
    if (!visible) {
      // Clear dismiss timer if exists
      if (dismissTimer) {
        clearTimeout(dismissTimer);
        dismissTimer = undefined;
      }
      // Schedule removal after animation
      removeTimer = setTimeout(() => {
        toastStore.removeToast(props.toast.id);
      }, props.toast.unmountDelay);
    }

    // run animate open/close
    if (!wrapperRef) return;
    const direction = getToastYDirection(props.toast, props.position);
    if (visible) {
      wrapperRef.animate(
        [
          { transform: `translate3d(0,${direction * -200}%,0) scale(.6)`, opacity: 0.5 },
          { transform: 'translate3d(0,0,0) scale(1)', opacity: 1 },
        ],
        {
          duration: 350,
          fill: 'forwards',
          easing: 'cubic-bezier(.21,1.02,.73,1)',
        },
      );
    } else {
      wrapperRef.animate(
        [
          { transform: 'translate3d(0,0,-1px) scale(1)', opacity: 1 },
          { transform: `translate3d(0,${direction * -150}%,-1px) scale(.4)`, opacity: 0 },
        ],
        {
          duration: 400,
          fill: 'forwards',
          easing: 'cubic-bezier(.06,.71,.55,1)',
        },
      );
    }
  });

  onCleanup(function cleanupToastTimersAndListeners() {
    if (dismissTimer) clearTimeout(dismissTimer);
    if (removeTimer) clearTimeout(removeTimer);
    // Gỡ event listeners
    if (props.toast.canPause && wrapperRef) {
      wrapperRef.removeEventListener('mouseenter', handleMouseEnter);
      wrapperRef.removeEventListener('mouseleave', handleMouseLeave);
    }
  });

  // Custom toast render
  const renderContent = () => {
    if (props.toast.type === 'custom' && typeof props.toast.message === 'function') {
      return (props.toast.message as (t: ToastData) => Element)(props.toast);
    }
    return <ToastBar toast={props.toast} position={props.position} />;
  };

  return (
    <div ref={wrapperRef} class="w-fit max-w-[350px]">
      {renderContent()}
    </div>
  );
};

// Position container
const PositionContainer: Component<{
  position: ToastPosition;
  toasts: ToastData[];
  gutter: number;
}> = props => {
  const getPositionStyles = (): JSX.CSSProperties => {
    const pos = props.position;
    const styles: JSX.CSSProperties = {
      gap: `${props.gutter}px`,
    };

    if (pos.includes('top')) {
      styles.top = '0';
    } else {
      styles.bottom = '0';
      styles['flex-direction'] = 'column-reverse';
    }

    if (pos.includes('left')) {
      styles.left = '0';
      styles['align-items'] = 'flex-start';
    } else if (pos.includes('right')) {
      styles.right = '0';
      styles['align-items'] = 'flex-end';
    } else {
      styles.left = '50%';
      styles.transform = 'translateX(-50%)';
      styles['align-items'] = 'center';
    }

    return styles;
  };

  return (
    <Show when={props.toasts.length > 0}>
      <div class="fixed z-9999 flex flex-col p-4" style={getPositionStyles()}>
        <For each={props.toasts}>
          {toast => <ToastWrapper toast={toast} position={props.position} />}
        </For>
      </div>
    </Show>
  );
};

// Internal Toaster component
const ToasterInternal: Component<ToasterProps> = props => {
  const position = () => props.position || 'top-right';
  const gutter = () => props.gutter ?? 10;

  // Group toasts by position
  const toastsByPosition = createMemo(() => {
    const currentToasts = toastStore.toasts();
    const groups: Record<ToastPosition, ToastData[]> = {
      'top-left': [],
      'top-center': [],
      'top-right': [],
      'bottom-left': [],
      'bottom-center': [],
      'bottom-right': [],
    };

    for (const t of currentToasts) {
      const pos = t.position || position();
      groups[pos].push(t);
    }

    return groups;
  });

  const positions: ToastPosition[] = [
    'top-left',
    'top-center',
    'top-right',
    'bottom-left',
    'bottom-center',
    'bottom-right',
  ];

  return (
    <>
      <For each={positions}>
        {pos => {
          const toastsForPos = createMemo(() => toastsByPosition()[pos]);
          return <PositionContainer position={pos} toasts={toastsForPos()} gutter={gutter()} />;
        }}
      </For>
    </>
  );
};

// Auto-mount toast container
let containerMounted = false;
let containerEl: HTMLDivElement | null = null;

const ensureContainer = () => {
  if (containerMounted) return;

  containerEl = document.createElement('div');
  containerEl.id = 'sui-toast-container';
  document.body.appendChild(containerEl);

  render(() => <ToasterInternal />, containerEl);
  containerMounted = true;
};

// Optional Toaster component for custom configuration
export const Toaster: Component<ToasterProps> = props => {
  onMount(() => {
    // If user adds Toaster, use their config
    if (!containerMounted) {
      containerEl = document.createElement('div');
      containerEl.id = 'sui-toast-container';
      document.body.appendChild(containerEl);

      render(() => <ToasterInternal {...props} />, containerEl);
      containerMounted = true;
    }
  });

  return null;
};

// Toast API
const createHandler =
  (type: ToastType) =>
  (message: Message, options?: ToastOptions): string => {
    ensureContainer();
    const toastData = toastStore.createToast(message, type, options);
    toastStore.upsertToast(toastData);
    return toastData.id;
  };

// Main toast function
const toast = ((message: Message, options?: ToastOptions): string => {
  return createHandler('blank')(message, options);
}) as ToastAPI;

toast.success = createHandler('success');
toast.error = createHandler('error');
toast.info = createHandler('info');
toast.warning = createHandler('warning');
toast.loading = createHandler('loading');

toast.custom = (message: (toast: ToastData) => JSX.Element, options?: ToastOptions): string => {
  ensureContainer();
  const toastData = toastStore.createToast(message as any, 'custom', options);
  toastStore.upsertToast(toastData);
  return toastData.id;
};

toast.dismiss = (toastId?: string) => {
  toastStore.dismissToast(toastId);
};

toast.remove = (toastId?: string) => {
  toastStore.removeToast(toastId);
};

toast.pop = (options?: { animate?: boolean }) => {
  if (options?.animate === false) {
    toastStore.removePop();
  } else {
    toastStore.dismissPop();
  }
};

toast.shift = (options?: { animate?: boolean }) => {
  if (options?.animate === false) {
    toastStore.removeShift();
  } else {
    toastStore.dismissShift();
  }
};

toast.promise = async <T,>(
  promise: Promise<T>,
  promiseOptions: PromiseOptions<T>,
  toastOptions?: ToastOptions,
): Promise<T> => {
  const id = toast.loading(promiseOptions.loading, toastOptions);

  try {
    const result = await promise;
    const successMessage = resolveValue(promiseOptions.success, result);
    toastStore.updateToast(id, {
      type: 'success',
      message: successMessage as any,
      icon: undefined, // Reset icon to use default success icon
    });
    // Schedule dismiss after showing success
    setTimeout(() => {
      toastStore.dismissToast(id);
    }, toastOptions?.duration ?? 3000);
    return result;
  } catch (error) {
    const errorMessage = resolveValue(promiseOptions.error, error);
    toastStore.updateToast(id, {
      type: 'error',
      message: errorMessage as any,
      icon: undefined, // Reset icon to use default error icon
    });
    // Schedule dismiss after showing error
    setTimeout(() => {
      toastStore.dismissToast(id);
    }, toastOptions?.duration ?? 3000);
    throw error;
  }
};

export { toast };
